const weekAgo = new Date(); weekAgo.setDate(weekAgo.getDate()-7);
const seen = new Set();
const items = $input.all().map(i=>i.json).filter(item => {
  const key = item.link || item.title;
  if (seen.has(key)) return false;
  seen.add(key);
  return !item.isoDate || new Date(item.isoDate) >= weekAgo;
}).map(i=>({ title: i.title, link: i.link, date: i.isoDate?.slice(0,10)||'', snippet: (i.contentSnippet||i.content||'').slice(0,200) })).slice(0,30);
return [{ json: { week: new Date().toISOString().slice(0,10), count: items.length, items } }];

