const data = $('Collect and Deduplicate').first().json;
let digest;
try { digest = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { digest = {}; }
return [{ json: { week: data.week, raw_count: data.count, generated_at: new Date().toISOString(), ...digest } }];

